@@ -438,6 +438,129 @@ select {
   background-repeat: no-repeat;
 }

+select.schemeSelect {
+  appearance: base-select;
+  padding-right: 12px;
+  background-image: none;
+}
+
+select.schemeSelect::picker(select) {
+  appearance: base-select;
+  background: var(--panel);
+  border: 1px solid var(--border);
+  border-radius: 14px;
+  padding: 6px;
+  box-shadow: 0 12px 24px rgba(0, 0, 0, 0.2);
+}
+
+select.schemeSelect::picker-icon {
+  color: var(--muted);
+  margin-inline-end: 10px;
+}
+
+select.schemeSelect::checkmark {
+  color: var(--accent);
+}
+
+select.schemeSelect option {
+  padding: 8px 10px;
+  border-radius: 10px;
+}
+
+select.schemeSelect option:checked {
+  background: color-mix(in srgb, var(--accent) 22%, transparent);
+}
+
+selectedcontent {
+  display: inline-flex;
+  align-items: center;
+  width: 100%;
+}
+
+.scheme-option {
+  display: inline-flex;
+  align-items: center;
+  justify-content: space-between;
+  width: 100%;
+  gap: 12px;
+}
+
+.scheme-chips {
+  display: inline-flex;
+  align-items: center;
+  gap: 4px;
+}
+
+.scheme-chips span {
+  width: 8px;
+  height: 8px;
+  border-radius: 999px;
+  background: var(--chip-1);
+  box-shadow: 0 0 0 1px color-mix(in srgb, var(--chip-1) 60%, transparent);
+}
+
+.scheme-chips span:nth-child(2) {
+  background: var(--chip-2);
+  box-shadow: 0 0 0 1px color-mix(in srgb, var(--chip-2) 60%, transparent);
+}
+
+.scheme-chips span:nth-child(3) {
+  background: var(--chip-3);
+  box-shadow: 0 0 0 1px color-mix(in srgb, var(--chip-3) 60%, transparent);
+}
+
+.scheme-chips span:nth-child(4) {
+  background: var(--chip-4);
+  box-shadow: 0 0 0 1px color-mix(in srgb, var(--chip-4) 60%, transparent);
+}
+
+selectedcontent .scheme-chips span {
+  width: 6px;
+  height: 6px;
+}
+
+.scheme-slate {
+  --chip-1: #4f76ff;
+  --chip-2: #1a2230;
+  --chip-3: #eaf0f8;
+  --chip-4: #aab6c9;
+}
+
+.scheme-cedar {
+  --chip-1: #c46b2a;
+  --chip-2: #221b16;
+  --chip-3: #f1e8dd;
+  --chip-4: #bdaea1;
+}
+
+.scheme-mint {
+  --chip-1: #2a9d8f;
+  --chip-2: #14201e;
+  --chip-3: #e4f3ef;
+  --chip-4: #a6bdb7;
+}
+
+.scheme-ocean {
+  --chip-1: #2b8db8;
+  --chip-2: #14222b;
+  --chip-3: #e0edf6;
+  --chip-4: #a7bfca;
+}
+
+.scheme-ember {
+  --chip-1: #d66a4a;
+  --chip-2: #261916;
+  --chip-3: #f3e4dc;
+  --chip-4: #c1aca3;
+}
+
+.scheme-iris {
+  --chip-1: #7b6cf6;
+  --chip-2: #1e1928;
+  --chip-3: #ece6f6;
+  --chip-4: #b4aeca;
+}
+
 input:focus,
 textarea:focus {
   border-color: var(--ui-focus);

